QMap<int, QVector<QString>> allOfUnicode;
QVector<SGEXTN::ApplicationBase::String> equivCodePointStorage;
QVector<SGEXTN::ApplicationBase::String> equivDecompStorage;
QVector<SGEXTN::ApplicationBase::String> compatCodePointStorage;
QVector<SGEXTN::ApplicationBase::String> compatDecompStorage;

void parseFile(){
    QString dataString = "";
    QFile file("../ApplicationBase/misc/unicode.txt");
    if(file.open(QIODevice::ReadOnly | QIODevice::Text)){
        dataString = file.readAll();
        file.close();
    }
    QVector<QString> characters = dataString.split('\n');
    for(int i=0; i<characters.length(); i++){
        QVector<QString> charData = characters.at(i).split(';');
        int codePoint = charData.at(0).toInt(nullptr, 16);
        charData.pop_front();
        allOfUnicode.insert(codePoint, charData);
    }
}

SGEXTN::ApplicationBase::String parseCodePointSequence(const QString& s){
    SGEXTN::ApplicationBase::String output;
    QString s0 = "";
    for(int i=0; i<s.length(); i++){
        if(SGEXTN::ApplicationBase::Character(static_cast<int>(s.at(i).unicode())).isDigit(16)){s0 += s.at(i);}
        else if(s.at(i) == ' '){
            if(s0 != ""){
                output += SGEXTN::ApplicationBase::Character(s0.toInt(nullptr, 16));
                s0 = "";
            }
        }
        else{qDebug() << "unexpected" << s;}
    }
    if(s0 != ""){output += SGEXTN::ApplicationBase::Character(s0.toInt(nullptr, 16));}
    return output;
}

SGEXTN::ApplicationBase::String convertQString(const QString& s){
    SGEXTN::ApplicationBase::String output;
    for(int i=0; i<s.length(); i++){
        output += SGEXTN::ApplicationBase::Character(static_cast<int>(s.at(i).unicode()));
    }
    return output;
}

void extractDecomp(){
    equivDecompStorage = QVector<SGEXTN::ApplicationBase::String>();
    compatDecompStorage = QVector<SGEXTN::ApplicationBase::String>();
    equivCodePointStorage = QVector<SGEXTN::ApplicationBase::String>();
    compatCodePointStorage = QVector<SGEXTN::ApplicationBase::String>();
    for(int i=0; i<=0x10ffff; i++){
        SGEXTN::ApplicationBase::String thisEquivDecomp;
        SGEXTN::ApplicationBase::String thisCompatDecomp;
        SGEXTN::ApplicationBase::String thisEquivCodePoint;
        SGEXTN::ApplicationBase::String thisCompatCodePoint;
        if(i >= 0xac00 && i <= 0xd7a3){
            int index = i - 0xac00;
            int leading = 0x1100 + (index / 588);
            int vowel = 0x1161 + ((index % 588) / 28);
            int trailing = index % 28;
            if(trailing == 0){trailing = -1;}
            else{trailing += 0x11a7;}
            thisEquivDecomp += SGEXTN::ApplicationBase::Character(leading);
            thisEquivCodePoint += SGEXTN::ApplicationBase::String::stringFromInt(leading, 16).fillLeftToCharacterLength(4, '0');
            thisEquivDecomp += SGEXTN::ApplicationBase::Character(vowel);
            thisEquivCodePoint += " ";
            thisEquivCodePoint += SGEXTN::ApplicationBase::String::stringFromInt(vowel, 16).fillLeftToCharacterLength(4, '0');
            if(trailing != -1){
                thisEquivDecomp += SGEXTN::ApplicationBase::Character(trailing);
                thisEquivCodePoint += " ";
                thisEquivCodePoint += SGEXTN::ApplicationBase::String::stringFromInt(trailing, 16).fillLeftToCharacterLength(4, '0');
            }
        }
        else if(allOfUnicode.contains(i) == true && allOfUnicode[i].at(4) != ""){
            QString rawDecomp = allOfUnicode[i].at(4);
            bool isCompat = false;
            if(rawDecomp.at(0) == '<'){
                isCompat = true;
                rawDecomp = rawDecomp.right(rawDecomp.length() - rawDecomp.lastIndexOf('>') - 2);
            }
            rawDecomp = rawDecomp.toLower();
            SGEXTN::ApplicationBase::String decomp = parseCodePointSequence(rawDecomp);
            SGEXTN::ApplicationBase::String codePoint = convertQString(rawDecomp);
            if(isCompat == false){
                thisEquivDecomp = decomp;
                thisEquivCodePoint = codePoint;
            }
            else{
                thisCompatDecomp = decomp;
                thisCompatCodePoint = codePoint;
            }
        }
        equivDecompStorage.push_back(thisEquivDecomp);
        compatDecompStorage.push_back(thisCompatDecomp);
        equivCodePointStorage.push_back(thisEquivCodePoint);
        compatCodePointStorage.push_back(thisCompatCodePoint);
    }
}

void logNewString(const SGEXTN::ApplicationBase::String& s){
    qDebug().noquote().nospace() << QString::fromUtf8(reinterpret_cast<const char*>(&s.private_data.byteAt(0)), s.byteLength());
}

void printDecomp(int start, bool compat){
    for(int i=start; i<=0x10ffff; i++){
        SGEXTN::ApplicationBase::String output;
        if(compat == false){
            if(equivDecompStorage.at(i) != ""){
                output += SGEXTN::ApplicationBase::Character(i);
                output += " --> ";
                output += equivDecompStorage.at(i);
                output += " | ";
                output += SGEXTN::ApplicationBase::String::stringFromInt(i, 16).fillLeftToCharacterLength(4, '0');
                output += " --> ";
                output += equivCodePointStorage.at(i);
            }
        }
        else{
            if(compatDecompStorage.at(i) != ""){
                output += SGEXTN::ApplicationBase::Character(i);
                output += " --> ";
                output += compatDecompStorage.at(i);
                output += " | ";
                output += SGEXTN::ApplicationBase::String::stringFromInt(i, 16).fillLeftToCharacterLength(4, '0');
                output += " --> ";
                output += compatCodePointStorage.at(i);
            }
        }
        if(output != ""){logNewString(output);}
    }
}

void checkDecomp(int end, bool compat){
    for(int i=0; i<=end; i++){
        SGEXTN::ApplicationBase::String output;
        if(compat == false){
            if(getEquivDecomp(i) != equivDecompStorage.at(i)){
                output += SGEXTN::ApplicationBase::String::stringFromInt(i, 16).fillLeftToCharacterLength(4, '0');
                output += " | ";
                output += equivCodePointStorage.at(i);
                output += " |";
                SGEXTN::ApplicationBase::String receivedResult = getEquivDecomp(i);
                SGEXTN::Containers::Array<int> codePoints = receivedResult.getUnicode();
                for(int j=0; j<codePoints.length(); j++){
                    output += " ";
                    output += SGEXTN::ApplicationBase::String::stringFromInt(codePoints.at(j), 16).fillLeftToCharacterLength(4, '0');
                }
            }
        }
        else{
            if(getCompatDecomp(i) != compatDecompStorage.at(i)){
                output += SGEXTN::ApplicationBase::String::stringFromInt(i, 16).fillLeftToCharacterLength(4, '0');
                output += " | ";
                output += compatCodePointStorage.at(i);
                output += " |";
                SGEXTN::ApplicationBase::String receivedResult = getCompatDecomp(i);
                SGEXTN::Containers::Array<int> codePoints = receivedResult.getUnicode();
                for(int j=0; j<codePoints.length(); j++){
                    output += " ";
                    output += SGEXTN::ApplicationBase::String::stringFromInt(codePoints.at(j), 16).fillLeftToCharacterLength(4, '0');
                }
            }
        }
        if(output != ""){logNewString(output);}
    }
}

void printTable(int start, int end, bool compat){
    SGEXTN::ApplicationBase::String output;
    int blankCodePoints = 0;
    output += "const char* lookup";
    if(compat == false){output += "Equiv";}
    else{output += "Compat";}
    output += "_0x";
    output += SGEXTN::ApplicationBase::String::stringFromInt(start, 16).fillLeftToCharacterLength(4, '0');
    output += "_to_0x";
    output += SGEXTN::ApplicationBase::String::stringFromInt(end, 16).fillLeftToCharacterLength(4, '0');
    output += "_Table[] = { ";
    for(int i=start; i<=end; i++){
        output += "U8(\"";
        SGEXTN::ApplicationBase::String targetString;
        if(compat == false){targetString = equivDecompStorage.at(i);}
        else{targetString = compatDecompStorage.at(i);}
        if(targetString == "" && SGEXTN::ApplicationBase::UnicodeQuery::getFullType(i) != SGEXTN::ApplicationBase::FullCharacterType::UnassignedCharacter){
            blankCodePoints++;
            logNewString(SGEXTN::ApplicationBase::String::stringFromInt(i, 16).fillLeftToCharacterLength(4, '0') + " is empty");
        }
        SGEXTN::Containers::Array<int> arr = targetString.getUnicode();
        for(int j=0; j<arr.length(); j++){
            int unicode = arr.at(j);
            if(unicode <= 0xffff){
                output += "\\u";
                output += SGEXTN::ApplicationBase::String::stringFromInt(unicode, 16).fillLeftToCharacterLength(4, '0');
            }
            else{
                output += "\\U";
                output += SGEXTN::ApplicationBase::String::stringFromInt(unicode, 16).fillLeftToCharacterLength(8, '0');
            }
        }
        output += "\")";
        if(i != end){output += ", ";}
    }
    output += " };";
    logNewString(output);
    float efficiency = 1.0f - (static_cast<float>(blankCodePoints) / static_cast<float>(end - start + 1));
    efficiency *= 100.0f;
    logNewString(SGEXTN::ApplicationBase::String::stringFromFloat(efficiency, 10, SGEXTN::ApplicationBase::FloatPrecisionFormat::DecimalPlace, 3) + "% efficiency");
}